create extension if not exists "pgcrypto";
create table if not exists public.users(id uuid primary key default gen_random_uuid(),name text not null,phone text unique not null,payment_method text not null check(payment_method in ('bkash','nagad')),password_hash text not null,referral_code text unique,host_id uuid,payout_limit numeric default 50,total_earnings numeric default 0,quiz_earnings numeric default 0,run_earnings numeric default 0,wheel_earnings numeric default 0,device_info text,ip_address text,created_at timestamptz default now(),is_vip boolean default false,is_banned boolean default false);
create table if not exists public.sessions(id uuid primary key default gen_random_uuid(),user_id uuid references public.users(id) on delete cascade,token text,device_fingerprint text,ip_address text,created_at timestamptz default now(),expires_at timestamptz);
create table if not exists public.game_history(id uuid primary key default gen_random_uuid(),user_id uuid references public.users(id) on delete cascade,game_type text,amount_earned numeric default 0,timestamp timestamptz default now(),session_id uuid);
create table if not exists public.wheel_spins(id uuid primary key default gen_random_uuid(),user_id uuid references public.users(id) on delete cascade,visual_result text,actual_result numeric,remaining_before numeric,remaining_after numeric,timestamp timestamptz default now());
create table if not exists public.quiz_submissions(id uuid primary key default gen_random_uuid(),user_id uuid references public.users(id) on delete cascade,answers jsonb,matched_keywords jsonb,earned_amount numeric,timestamp timestamptz default now());
create table if not exists public.dino_run_sessions(id uuid primary key default gen_random_uuid(),user_id uuid references public.users(id) on delete cascade,coins_collected jsonb,duration numeric,earned_amount numeric,timestamp timestamptz default now());
create table if not exists public.leaderboard(id uuid primary key default gen_random_uuid(),name text,earnings numeric,is_real boolean default false,rank integer,badge text);
create table if not exists public.admins(id uuid primary key default gen_random_uuid(),username text unique,password_hash text not null,permissions jsonb default '{}'::jsonb);
create table if not exists public.referral_hosts(id uuid primary key default gen_random_uuid(),user_id uuid references public.users(id) on delete cascade,referral_code text unique,referral_link text,total_invites integer default 0,invited_users jsonb default '[]'::jsonb,custom_payout_cap numeric default 50,created_at timestamptz default now());
alter table public.users add constraint users_host_fk foreign key(host_id) references public.referral_hosts(id);
create table if not exists public.global_settings(id integer primary key default 1,default_payout_cap numeric default 50,vip_payout_cap numeric default 100,coin_spawn_rate numeric default 65,wheel_enabled boolean default true,dino_enabled boolean default true,ticker_messages jsonb default '[]'::jsonb,last_updated timestamptz default now(),updated_by uuid);
create or replace function public.recalc_user_total(p_user_id uuid) returns void language plpgsql security definer as $$ begin update public.users set total_earnings=coalesce(quiz_earnings,0)+coalesce(run_earnings,0)+coalesce(wheel_earnings,0) where id=p_user_id; end; $$;
create or replace function public.add_quiz_reward(p_user_id uuid,p_amount numeric,p_answers jsonb,p_matched jsonb) returns void language plpgsql security definer as $$ begin update public.users set quiz_earnings=quiz_earnings+p_amount where id=p_user_id; insert into public.quiz_submissions(user_id,answers,matched_keywords,earned_amount) values(p_user_id,p_answers,p_matched,p_amount); insert into public.game_history(user_id,game_type,amount_earned) values(p_user_id,'quiz',p_amount); perform public.recalc_user_total(p_user_id); end; $$;
create or replace function public.add_dino_reward(p_user_id uuid,p_amount numeric,p_coins jsonb,p_duration numeric) returns void language plpgsql security definer as $$ begin update public.users set run_earnings=run_earnings+p_amount where id=p_user_id; insert into public.dino_run_sessions(user_id,coins_collected,duration,earned_amount) values(p_user_id,p_coins,p_duration,p_amount); insert into public.game_history(user_id,game_type,amount_earned) values(p_user_id,'dino',p_amount); perform public.recalc_user_total(p_user_id); end; $$;
create or replace function public.add_wheel_reward(p_user_id uuid,p_amount numeric,p_visual text,p_before numeric) returns void language plpgsql security definer as $$ begin update public.users set wheel_earnings=wheel_earnings+p_amount where id=p_user_id; insert into public.wheel_spins(user_id,visual_result,actual_result,remaining_before,remaining_after) values(p_user_id,p_visual,p_amount,p_before,p_before-p_amount); insert into public.game_history(user_id,game_type,amount_earned) values(p_user_id,'wheel',p_amount); perform public.recalc_user_total(p_user_id); end; $$;
alter table public.users enable row level security;alter table public.game_history enable row level security;alter table public.leaderboard enable row level security;
create policy "leaderboard public read" on public.leaderboard for select using (true);
